// Execute a tree-sitter query pattern against a parsed tree.
//
// The `query_source` is an S-expression pattern like:
// ```text
// (function_definition name: (identifier) @name)
// ```
//
// Returns all matches with their captured nodes.
//
// # Arguments
//
// * `tree` - The parsed syntax tree to query.
// * `language` - Language name (used to compile the query pattern).
// * `query_source` - The tree-sitter query pattern string.
// * `source` - The original source code bytes (needed for capture resolution).
//
// # Examples
//
// ```no_run
// let tree = tree_sitter_language_pack::parse_string("python", b"def hello(): pass").unwrap();
// let matches = tree_sitter_language_pack::run_query(
// &tree,
// "python",
// "(function_definition name: (identifier) @fn_name)",
// b"def hello(): pass",
// ).unwrap();
// assert!(!matches.is_empty());
// ```
func RunQuery(tree *Tree, language string, query_source string, source []byte) (*[]QueryMatch, error) {
	cTree := (*C.TS_PACKTree)(unsafe.Pointer(tree.ptr))

	cLanguage := C.CString(language)
	defer C.free(unsafe.Pointer(cLanguage))

	cQuerySource := C.CString(query_source)
	defer C.free(unsafe.Pointer(cQuerySource))

	cSource := (*C.uint8_t)(unsafe.Pointer(&source[0]))
	cSourceLen := C.uintptr_t(len(source))

	ptr := C.ts_pack_run_query(cTree, cLanguage, cQuerySource, cSource, cSourceLen)
	if err := lastError(); err != nil {
		return nil, err
	}
	return func() *[]QueryMatch {
	if ptr == nil { return nil }
	defer C.ts_pack_free_string(ptr)
	var result []QueryMatch
	if err := json.Unmarshal([]byte(C.GoString(ptr)), &result); err != nil { return nil }
	return &result
}(), nil
}


